class Solution:
    def characterReplacement(self, s: str, k: int) -> int:
        cnt = [0]*26
        l = maxf = ans = 0
        for r, ch in enumerate(s):
            cnt[ord(ch)-65] += 1
            maxf = max(maxf, cnt[ord(ch)-65])
            while r - l + 1 - maxf > k:
                cnt[ord(s[l])-65] -= 1
                l += 1
            ans = max(ans, r - l + 1)
        return ans

