class Solution {
public:
    int characterReplacement(string s, int k) {
        int cnt[26]={}, l=0, maxf=0, ans=0;
        for(int r=0;r<(int)s.size();r++){
            cnt[s[r]-'A']++;
            maxf=max(maxf,cnt[s[r]-'A']);
            while(r-l+1-maxf>k){ cnt[s[l]-'A']--; l++; }
            ans=max(ans,r-l+1);
        }
        return ans;
    }
};

