int characterReplacement(char* s, int k) {
    int cnt[26]={0}, l=0, maxf=0, ans=0, n=strlen(s);
    for(int r=0;r<n;r++){
        cnt[s[r]-'A']++; if(cnt[s[r]-'A']>maxf) maxf=cnt[s[r]-'A'];
        while(r-l+1-maxf>k){ cnt[s[l]-'A']--; l++; }
        if(r-l+1>ans) ans=r-l+1;
    }
    return ans;
}
